import subprocess
from poetry.core.semver import Version
from poetry.core.source import Source
from poetry.core.packaging.version import VersionSpec
from poetry.repositories import Repository

def generate_lock_file():
    """
    Generate a Poetry lock file using the current `requirements.txt` file.
    
    This script is used to generate or update the dependency specifications for our project.
    It ensures that all dependencies are locked at specific versions, so we can reproduce 
    the same environment in development and production.
    """

    # Install poetry
    subprocess.run(["pip", "install", "--user", "poetry"])

    # Navigate to the project directory
    subprocess.run(["cd", "."])

    # Initialize poetry
    subprocess.run(["poetry", "init"])

    # Create a `pyproject.toml` file with the following content:
    pyproject_content = """
[tool.poetry]
name = "your_project_name"
version = "1.0.0"

[tool.poetry.dependencies]
python = "^3.8"

[tool.poetry.dev-dependencies]
"""

    # Write the `pyproject.toml` file
    with open("pyproject.toml", "w") as f:
        f.write(pyproject_content)

    # Install all dependencies from requirements.txt
    subprocess.run(["pip-compile", "--output-file=requirements.in"])

    # Update pyproject.toml to include the dependencies
    subprocess.run(["poetry", "update"])

    # Generate a lock file
    subprocess.run(["poetry", "lock"])

def update_lock_file():
    """
    Update the Poetry lock file using the current `requirements.txt` file.
    
    This script is used to generate or update the dependency specifications for our project.
    It ensures that all dependencies are locked at specific versions, so we can reproduce 
    the same environment in development and production.
    """

    # Install poetry
    subprocess.run(["pip", "install", "--user", "poetry"])

    # Navigate to the project directory
    subprocess.run(["cd", "."])

    # Initialize poetry
    subprocess.run(["poetry", "init"])

    # Update pyproject.toml to include all dependencies from requirements.txt
    with open("requirements.in", "r") as f:
        lines = f.readlines()

    new_dependencies = []
    for line in lines:
        # Get the package name and version
        package_name, _, version = line.partition("=")
        package_name = package_name.strip()
        version = version.strip()

        # Find the corresponding dependency in pyproject.toml
        with open("pyproject.toml", "r") as g:
            pyproject_content = g.read()
            lines = pyproject_content.splitlines()
            for i, line in enumerate(lines):
                if line.startswith("[tool.poetry.dependencies]"):
                    dependencies_lines = []
                    while True:
                        next_line = lines[i + 1]
                        if next_line.startswith("[") or next_line == "":
                            break
                        dependencies_lines.append(next_line)
                    dependency_content = "".join(dependencies_lines).strip()
                    import ast
                    dependencies_dict = ast.literal_eval(dependency_content)

                    # Check if the package is already a dependency
                    if package_name in dependencies_dict:
                        print(f"{package_name} is already a dependency at version {dependencies_dict[package_name]}")
                        continue

                if line.startswith(package_name):
                    lines[i] = f"# Commenting out the existing dependency to update it\n"
                    continue

        # Add the new dependency to pyproject.toml
        with open("pyproject.toml", "a") as h:
            h.write(f"[tool.poetry.dependencies]\n{package_name} = {version}\n\n")

    # Generate a lock file
    subprocess.run(["poetry", "lock"])